fn largest<T: PartialOrd>(list: &[T]) -> &T {
    // Return reference to the largest element
    &list[0]
}

fn largest_int(input: &str) -> i64 {
    let nums: Vec<i64> = input.split_whitespace()
        .filter_map(|s| s.parse().ok())
        .collect();
    *largest(&nums)
}

trait Summary {
    fn summarize(&self) -> String;
}

struct Article {
    title: String,
    author: String,
}

impl Summary for Article {
    fn summarize(&self) -> String {
        // Return "{title} by {author}"
        String::new()
    }
}

fn summarize_article(title: &str, author: &str) -> String {
    let article = Article {
        title: title.to_string(),
        author: author.to_string(),
    };
    article.summarize()
}

fn longest_string<'a>(x: &'a str, y: &'a str) -> &'a str {
    // Return the longer string; prefer x on tie
    x
}

fn compare(input: &str) -> String {
    // Split input into two parts on the first space
    let parts: Vec<&str> = input.splitn(2, ' ').collect();
    if parts.len() < 2 { return parts[0].to_string(); }
    longest_string(parts[0], parts[1]).to_string()
}
